Finset.card_insertNthEquiv_filter_piFinset.{u_1} {n : ℕ} {α : Fin (n + 1) → Type u_1} {p : Fin (n + 1)}
  (S : (i : Fin (n + 1)) → Finset (α i)) (P : ((i : Fin n) → α (p.succAbove i)) → Prop) [DecidablePred P] :
  #({r ∈ Fintype.piFinset S | P (p.removeNth r)}) = #(S p) * #({r ∈ Fintype.piFinset (p.removeNth S) | P r})

